var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"대답이 없으셔서 걱정했습니다. 아직 방에 남아 계셨군요.","JPN":"返事がないので心配しました。まだお部屋にいらっしゃいましたか。","ENG":"You didn't answer, so I was a bit worried. Still in your room, I see.","TWN":"你沒有回應，我很擔心。原來你還在房間裡啊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"쓰지 않던 글까지 쓰시고, 무슨 일이십니까?","JPN":"珍しく書き物などされて、どうなさったんですか？","ENG":"Even writing something? That's not like you. Is something wrong?","TWN":"連不常寫的信都寫了，發生什麼事了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"현 전황을 분석하며 유용할 법한 전술을 추리고 있었습니다.","JPN":"現在の戦況を分析し、使えそうな戦術を選んでいるところです。","ENG":"Just reviewing the current situation and jotting down some useful tactics.","TWN":"正在分析當前戰況，並篩選出可能有用的戰術。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"간략하게 적은 병서에 불과하지만, 알렌이라면 이조차 유의미하게 사용해주겠죠.","JPN":"簡単に書き込んだ兵書にすぎませんが、アレンならこれを有効に活用してくれるでしょう。","ENG":"It's a brief draft of strategies, but if it's Allen, even this should come in handy.","TWN":"雖然只是簡略的兵書，但如果是艾倫的話，即使這樣也會有意義地使用吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"괜찮을까요? 백작님께서 워낙 스파르타식으로 가르치신 탓에.","JPN":"大丈夫なんですか？　伯爵からスパルタ式に叩き込まれたせいで。","ENG":"You think so? You trained him so strictly,","TWN":"沒問題嗎？伯爵大人的教導太過嚴厲，"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"아직도 단장님께서는 병서만 보시면 낯빛이 창백해지시던데요.","JPN":"いまだに団長は兵書を見るだけで顔色が悪くなるんです。","ENG":"that he still turns pale at the sight of a strategy manual.","TWN":"團長一看到兵書，臉色還是會變得蒼白呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전쟁에 전술만큼이나 중요한 것은 없습니다. 그리고 스파르타가 아니라 애정이에요.","JPN":"戦争で戦術学ほど重要なものはありません。それに、あれはスパルタではなく愛情ですよ。","ENG":"Nothing's more important in war than sound tactics. And it wasn't strictness, it was love.","TWN":"在戰爭中，沒有什麼比戰術學更重要的了。而且，這不是嚴厲，而是愛。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"루지에 경도 저처럼 헌신적인 아내가 생겨야 이 기분을 이해하실 텐데… 안타깝군요.","JPN":"ルージ卿も私のように献身的な妻を持てばこの気持ちがわかるはずですが……残念です。","ENG":"Sir Rougié needs a devoted wife like me to truly understand... A shame, really.","TWN":"你也需要有像我這樣的賢妻才能理解這種心情吧……真是遺憾呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"혹시 죽을병에라도 걸리셨습니까?","JPN":"不治の病にでも罹られたんですか？","ENG":"Are you dying or something?","TWN":"難道得了什麼絕症嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 사실 이건 병서가 아니라 유서였답니다.","JPN":"ええ。実はこれは兵書ではなく、遺書なのです。","ENG":"Yes, in fact. This isn't a strategy book. It's my will.","TWN":"是的，其實這不是兵書，而是遺書。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"마침 루지에 경을 해고시켜달라고 적는 참이었지요.","JPN":"ちょうどルージ卿の解雇を願う文面をしたためているところでした。","ENG":"I was just writing a request to have Sir Rougié dismissed.","TWN":"我正在寫信請求解雇路吉爾卿呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"마지막까지 예술로 가시는군요, 참.","JPN":"去り際まで見事ですね。はあ。","ENG":"Even your final moments are dramatic.","TWN":"最後還是選擇了藝術之路啊，真是的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 농담이랍니다.","JPN":"ふふ、冗談です。","ENG":"Haha, I'm joking.","TWN":"呵呵，我開玩笑的喔。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무엇보다 생을 마감한다면 사랑하는 이가 준비해준 자리에서 눈을 감을 생각이라서요.","JPN":"なにより一生を終える時には、愛する人が用意してくれた場所で眠るつもりなのです。","ENG":"If I really were dying, I'd want to peacefully go somewhere my beloved prepared for me.","TWN":"最重要的是，如果要結束生命，我想在愛人為我準備的地方閉上眼睛。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"이번 탄신일에 단장님께 묘비라도 선물해달라고 하시게요?","JPN":"今度のお誕生日に、団長に墓石でもプレゼントしてもらうおつもりですか？","ENG":"You're planning to ask the captain for a gravestone on your birthday?","TWN":"這次生日要不要送團長一塊墓碑呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그것도 퍽 로맨틱하겠군요. 진지하게 고려해보겠습니다.","JPN":"それもロマンチックですね。真剣に考えてみます。","ENG":"Isn't that a romantic gesture? I'll think about it.","TWN":"那也挺浪漫的。我會認真考慮的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"그건 상관없는데, 제 아이디어였다고는 말하지 말아주십쇼.","JPN":"それはいいですけど、私のアイデアだなんて言わないでくださいよ。","ENG":"Fine, just don't tell anyone it was my idea.","TWN":"這個不是問題，但請不要說是我的主意。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"자, 장난은 이쯤하고 그만 본론으로 넘어가지요.","JPN":"さて、冗談はここまでにして本題に入りましょうか。","ENG":"E-enough joking. Let's get back to business.","TWN":"好了，玩笑到此為止，我們還是進入正題吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부탁했던 건 어떻게 됐나요?","JPN":"頼んでいたものはどうなりました？","ENG":"How did the preparations go?","TWN":"我拜託你的事情怎麼樣了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"백작령을 지킬 병사들을 제외한 원정대의 편성을 끝마쳤습니다.","JPN":"伯爵領を守る兵士を除いて遠征隊を編成しました。","ENG":"The expedition is assembled, minus the troops staying to defend the County.","TWN":"除了保護伯爵領地的士兵外，遠征隊的編制已經完成。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"마지막 남은 처녀자리의 무구가 완성되면 마침내 열두 무구의 선별이 끝나는군요.","JPN":"残る乙女座の武具が完成すれば、12武具の選別は終わりです。","ENG":"Once the remaining Virgo Armament is complete, we'll have all twelve chosen.","TWN":"最後一件處女座的聖遺物完成後，十二聖遺物的選拔終於結束了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"제국 신민들이 염원하던 계승식도 무사히 거행될 것입니다.","JPN":"帝国の臣民が待ち望んでいた継承式も無事行われるでしょう。","ENG":"The succession ceremony the Empire's people have long awaited can finally begin.","TWN":"帝國臣民們所期盼的繼承儀式也將順利舉行。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……예. 그렇겠죠.","JPN":"……ええ、そうでしょうね。","ENG":"...Yes. It can.","TWN":"是的，沒錯。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제가 곧 갈 터이니, 루지에 경은 백작령에 남을 기사들을 인솔해주시길 바랍니다.","JPN":"すぐに向かいますので、ルージ卿は伯爵領に残る騎士たちをお願いします。","ENG":"I'll be leaving soon. Sir Rougié, I'm entrusting the remaining knights to you.","TWN":"我馬上就去，請路吉爾率領留在伯爵領地的騎士們。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"예. 받들겠습니다.","JPN":"はい。承知いたしました。","ENG":"Understood.","TWN":"是。我會遵從的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"루지에 경. 잠시 괜찮을까요?","JPN":"ルージ卿。少しいいでしょうか？","ENG":"Sir Rougié, one more thing.","TWN":"路吉爾卿。打擾一下？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"네. 말씀하시죠.","JPN":"はい。なんなりと。","ENG":"Yes?","TWN":"請說。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"별거 아니에요. 항상 신경 써줘서 고맙다고요.","JPN":"大したことではありません。いつも気遣っていただきありがとうございます。","ENG":"It's nothing big. Just... thank you. For everything.","TWN":"沒什麼。我只是想說謝謝你一直以來的關心。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"……정말 죽을병에라도 걸리셨습니까?","JPN":"……本当に不治の病にでも罹られたのですか？","ENG":"...Are you sure you're not dying?","TWN":"……真的得了絕症嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"너무해라. 알렌이 오면 일러바칠 거예요?","JPN":"酷いわ。アレンが来たら言いつけますよ？","ENG":"That's harsh. I'm telling Allen when he gets back.","TWN":"太過分了。等艾倫來了我要告狀！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"제가 뭐 잘못했습니까? 하다하다 이런 식으로 욕을 먹인다고요?","JPN":"私、何か間違ったことでも？　こんな罰、あり得ます？","ENG":"What did I do?! You're making me the bad guy again!","TWN":"我做錯了什麼嗎？居然用這種方式來罵我？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"농담이에요. 제가 없는 동안 백작령을 잘 부탁드려요.","JPN":"冗談です。私がいない間、伯爵領をよろしくお願いします。","ENG":"I'm teasing. Please take care of the County while I'm gone.","TWN":"開玩笑啦。我不在的時候，就拜託你照顧伯爵領地了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 욕심에 취한 자들을 숱하게 봐왔거늘. 박명 앞에서는 나도 한낱 인간에 불과하구나.","JPN":"欲に染まった者は数えきれないほど見てきたのに。薄命の前では私もただの人間ね。","ENG":"I've seen so many people consumed by greed. But in the face of death, I'm just human too.","TWN":"我見過無數被欲望迷惑的人。然而在命運面前，我也不過是個凡人罷了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이것이 별의 주마등이라면, 하다못해 당신이 나오는 꿈이라면 좋으련만.","JPN":"これが星の走馬灯なら、せめて貴方が出る夢であってほしいわ。","ENG":"If this is the starlight of my final hour, I hope I at least dream of you.","TWN":"如果這是星星的走馬燈，至少希望夢裡能出現你。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오늘따라 당신이 보고 싶네요.","JPN":"今日はなぜか貴方にとても会いたい。","ENG":"Strange, I miss you today.","TWN":"今天特別想見你呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……알렌.","JPN":"……アレン。","ENG":"...Allen.","TWN":"……艾倫。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인. 준비를 끝마쳤습니다.","JPN":"夫人。準備ができました。","ENG":"Ma'am. I'm ready.","TWN":"夫人，已經準備好了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제가 어디로 가면 되겠습니까?","JPN":"私はどこに行けばいいのですか？","ENG":"Where should I go?","TWN":"我應該去哪裡？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"잠시 기다려 주시지요. 제가 안내하겠습니다.","JPN":"少々お待ちください。私がご案内しましょう。","ENG":"Please wait a moment. I'll take you myself.","TWN":"請稍等，我來為你指引。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"좋은 아침입니다, 에스텔. 간밤에 잠은 잘 주무셨는지요?","JPN":"おはようございます、エステル。ぐっすり眠れましたか？","ENG":"Good morning, Esther. Did you sleep well?","TWN":"早上好，艾斯特。昨晚睡得好嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……머리맡에 참새 잠옷이 들어가 있더군요.","JPN":"……枕元にスズメのパジャマがありました。","ENG":"...There was a bird onesie by my pillow.","TWN":"……枕邊放著麻雀睡衣呢。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"핑크 로빈이라는 종입니다. 경께서 로브를 입은 모습이 퍽 비슷해서 말이지요.","JPN":"ピンクロビンという鳥です。卿がローブを被っている姿ととてもよく似ていたもので。","ENG":"That bird is called a pink robin. You reminded me of one in that robe.","TWN":"這是一種叫做粉紅知更鳥的品種。因為你穿著斗篷的樣子和它很相似，所以才這麼說的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"궁중 재단사에게 일러 하룻밤 사이에 만들었는데, 어떠셨습니까?","JPN":"宮廷の仕立屋に命じて一晩で作らせたのですが、お気に召しましたか？","ENG":"I had it made overnight by the court tailor. What did you think?","TWN":"讓宮廷裁縫在一夜之間製作出來，你覺得怎麼樣？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건…… 입어보지 않아 모르겠습니다.","JPN":"それは……着なかったのでわかりません。","ENG":"I didn't wear it... so I'm not sure.","TWN":"那個……沒試過所以不知道。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 그런가요?","JPN":"ふふ。そうですか。","ENG":"Haha, is that so?","TWN":"呵呵，是這樣嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다음에는 좀 더, 경의 취향을 고려할 필요가 있겠습니다.","JPN":"今度はもっと、卿の好みを考慮しましょう。","ENG":"Next time, I'll consider your taste more carefully.","TWN":"下次需要更加考慮你的喜好。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"백작님께서 도착하셨다. 전원, 도열!","JPN":"伯爵がお見えになった。全員、整列！","ENG":"The Countess has arrived! All units, form up!","TWN":"伯爵大人到達了。全員，列隊！"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"출정 준비를 끝마쳤습니다, 백작님!","JPN":"出征の準備が終わりました、伯爵！","ENG":"Expedition preparations complete, Countess!","TWN":"出征準備完成，伯爵大人！"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"원정이란 걸 알아도 굉장한 수로군요.","JPN":"遠征であることは承知していますが、相当な数ですね。","ENG":"Even knowing it's an expedition, this is quite the force.","TWN":"即使知道是遠征，數量還真是驚人。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이 정도면 족히 수만 명은 되어 보입니다.","JPN":"これならゆうに数万はいきそうです。","ENG":"There must be tens of thousands here.","TWN":"這些應該足夠有數萬人了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"일의 중요성을 생각하면 턱없이 부족한 수입니다.","JPN":"事の重要性を考慮すれば、まったく足りません。","ENG":"For something this important, it's still not enough.","TWN":"考慮到事情的重要性，這個數量還是遠遠不夠的。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"앞서 원정을 떠난 동료들을 기다리고 싶으나, 시간이 걸리는 모양이니 어쩔 수 없지요.","JPN":"先に遠征に出た者たちを待ちたかったのですが、時間の関係上仕方ありません。","ENG":"I wish we could wait for the others who left earlier, but we're out of time.","TWN":"雖然想等待先前出征的同伴，但看來需要時間，沒辦法了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"버밍엄 백작님. 병사들이 출전명령을 기다리고 있습니다.","JPN":"バーミンガム伯爵、兵士が出征命令を待っております。","ENG":"Countess Birmingham, the soldiers await your command.","TWN":"伯明罕伯爵大人。士兵們正在等待出征命令。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"페론 경. 이제부터는 기사로서 나아가야 할 때입니다.","JPN":"ペロン卿、今から私は騎士です。","ENG":"Sir Ferron. From this point forward, we march as knights.","TWN":"費隆卿。現在是時候以騎士的身份前進了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부족하지만 예우를 갖춰 주시지요. 저 또한 여러분과 뜻을 함께하는 동료가 아닙니까?","JPN":"足りない私ですが、この場にふさわしい待遇をお願いします。私もまた皆さんと意志を共にする仲間ではありませんか。","ENG":"I ask for your respect, even if I fall short. I'm one of you, after all.","TWN":"雖然不夠完美，但請給予我應有的禮遇。我也是與你們志同道合的夥伴，不是嗎？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"……실례했습니다, 그레이스 경.","JPN":"……失礼いたしました、グレース卿。","ENG":"...Forgive me, Dame Grace.","TWN":"……抱歉，葛瑞絲小姐。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"부디, 명령을.","JPN":"どうか、ご命令を。","ENG":"Please, your orders.","TWN":"請下達命令。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"불타버린 여덟 대륙에서 모인 기사 여러분.","JPN":"燃えてしまった八つの大陸から集まった騎士の皆さん。","ENG":"Knights from the eight continents that burned.","TWN":"從燃燒的八大洲聚集而來的騎士們。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"여러분은 패배자입니다.","JPN":"皆さんは敗北者です。","ENG":"You are all failures.","TWN":"你們是失敗者。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"조용. 백작님께서 말씀 중이십니다.","JPN":"静かに。伯爵がお話中です。","ENG":"Silence. The Countess is speaking.","TWN":"安靜。伯爵大人在說話。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"혹자는 힘에 굴복하여 가족을 잃고, 혹자는 두려움에 떨며 고향을 버리고 도망쳤으며.","JPN":"ある者は力に屈して家族を失い、ある者は恐怖に怯えて故郷を捨て。","ENG":"Some of you lost your families to overwhelming force. Some fled your homes in fear.","TWN":"有的人因屈服於力量而失去了家人，有的人因恐懼而拋棄故鄉逃跑。"},"stage":{"bg":"CASTLE_03","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"혹자는, 스스로의 나약함을 버티지 못해 주변으로부터의 손을 뿌리쳤습니다.","JPN":"またある者は、自分の弱さに耐えられず周りの手を振りほどきました。","ENG":"Some couldn't bear your own weakness and pushed others away.","TWN":"有些人因為無法忍受自己的軟弱，拒絕了周圍的幫助。"},"stage":{"bg":"CASTLE_03","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"여덟 대륙이 불타 없어지는 동안, 여러분은 어떤 불의에도 맞서 싸우지 못했습니다.","JPN":"八つの大陸が燃え去る間、皆さんはどんな不当にも立ち向かうことができませんでした。","ENG":"While the eight continents burned, you stood by and did nothing.","TWN":"在八大洲燃燒殆盡的過程中，你們未能抵抗任何火焰。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그 결과. 동포들이 목숨을 걸고 싸우고 있는 지금, 백작령에서 제 몫만 축내고 있지요.","JPN":"その結果。仲間が命を懸けて戦っている今、伯爵領でのうのうと過ごしています。","ENG":"And now, while others fight and die, you sit safely here in the County.","TWN":"結果是，在同胞們拼命戰鬥的時候，我卻在伯爵領地裡虛度光陰。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그대들이 마지막으로 기억하는 광경은 무엇입니까?","JPN":"貴方たちが最後に覚えている光景は何でしょうか？","ENG":"What do you remember last?","TWN":"你們最後記得的景象是什麼？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전쟁과 기근 없이 평화로운 삶을 누릴 수 있는 백작령의 모습입니까?","JPN":"戦争と飢饉のない、平和な暮らしのできる伯爵領の光景ですか？","ENG":"Was it the peaceful County, untouched by war and famine?","TWN":"這是一個沒有戰爭和饑荒，可以享受和平生活的伯爵領地的樣子嗎？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아니면, 죽은 동료와 가족이 내뱉는 비명 섞인 전장입니까?","JPN":"それとも、死んだ仲間と家族の悲鳴が混ざった戦場ですか？","ENG":"Or was it the battlefield, where your comrades and loved ones screamed?","TWN":"還是說，那是死去的同伴和家人發出的夾雜著尖叫的戰場呢？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"200년 만에 비로소 세계가 선택한 구원자가 우리 앞에 모습을 드러냈으나.","JPN":"200年ぶりにやっと世界が選択した救世主が私たちの前に姿を現しましたが。","ENG":"For the first time in two centuries, the world's chosen savior stands before us.","TWN":"200年後，世界終於選擇的救贖主出現在我們面前。"},"stage":{"bg":"MS_901","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그는 세계를 구원할 뿐. 모두를 죽음으로부터 지켜주는 존재가 아닙니다.","JPN":"彼は世界を救うだけ。皆さんを死から守ってくれる存在ではありません。","ENG":"But he won't protect you from death. He's here to save the world.","TWN":"他只是拯救世界的人，並不是保護所有人免於死亡的存在。"},"stage":{"bg":"MS_901","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그대들의 죽은 동료와 가족이 남기고자 했던 희망의 별빛을.","JPN":"貴方たちの死んだ仲間と家族が残そうとしていた希望の星の光を。","ENG":"Will you let the starlight of hope your fallen comrades left behind...","TWN":"你們那些已故的同伴和家人想要留下的希望之星。"},"stage":{"bg":"MS_901","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세계를 구원하는 대가로 짓밟히게 내버려둘 것입니까?","JPN":"世界を救う代償として踏みにじらせておいて良いのですか？","ENG":"Be trampled as the price of that salvation?","TWN":"為了拯救世界，你會任由自己被踐踏嗎？"},"stage":{"bg":"MS_901","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다같이 살아 돌아오자는 무책임한 소리는 하지 않겠습니다.","JPN":"全員生きて帰ってこようなどと無責任なことは言いません。","ENG":"I won't say something naive like, \\"Let's all come back alive.\\"","TWN":"我不會說什麼大家一起活著回來這種不負責任的話。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그저 앞서 떠난 동료들의 죽음에 가치를 새기기 위해.","JPN":"ただ先に亡くなった仲間たちの死に価値を与えるため。","ENG":"But to honor those who've already fallen...","TWN":"只是為了銘記那些先行離去的同伴們的價值。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그들이 걸어간 길에 정의를 새기기 위해…….","JPN":"彼らの歩んだ道に正義を刻むため……","ENG":"To etch justice into their path...","TWN":"為了在他們走過的路上銘刻正義……"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"여러분의 힘을 제게 빌려주시지요.","JPN":"皆さんの力を私に貸してください。","ENG":"Lend me your strength.","TWN":"請大家借給我力量吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"1번대 대장, 딜란. 그레이스 경을 따르겠습니다.","JPN":"第1番隊長、ディラン。グレース卿に従います。","ENG":"First captain, Dylan. I will follow Dame Grace.","TWN":"第一小隊隊長，迪蘭。我會追隨葛瑞絲小姐。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L31_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"2번대 대장, 윌리엄. 그레이스 경을 따르겠습니다!","JPN":"第2番隊長、ウィリアム。グレース卿に従います！","ENG":"Second captain, William. I will follow Dame Grace!","TWN":"第二小隊隊長，威廉。我會追隨葛瑞絲小姐！"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"제국의 안녕을 위해, 그레이스 경을 따르겠습니다!!","JPN":"帝国の平穏のため、グレース卿に従います！！","ENG":"For the Empire's peace, I will follow Dame Grace!!","TWN":"為了帝國的安寧，我將追隨葛瑞絲小姐！！"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"이해할 수 없다는 표정을 짓고 계시는군요.","JPN":"理解できないというお顔ですね。","ENG":"You look confused.","TWN":"你露出了無法理解的表情。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"확실히, 저희 같은 오합지졸들이 기사 행세를 하고 다니는 것이 우스우실 겁니다.","JPN":"確かに、私たちのような烏合の衆が騎士の真似ごとをしている姿は滑稽でしょう。","ENG":"We must look ridiculous. Ragtag knights pretending we belong.","TWN":"確實，像我們這樣的烏合之眾裝成騎士到處走，你一定覺得很可笑吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오해할 만한 행동이었다면 죄송합니다.","JPN":"誤解を招くような行動だったら申し訳ありません。","ENG":"If I gave that impression, I'm sorry.","TWN":"如果我的行為讓你誤會了，我很抱歉。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그저… 이토록 많은 이들이 저분께 목숨을 맡기고 있다는 것이 놀라웠습니다.","JPN":"ただ……このように多くの人があの方に命を預けていることに驚いていました。","ENG":"I'm just... amazed so many would entrust their lives to her.","TWN":"只是……這麼多人竟然願意把性命託付給她，真是令人驚訝。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"이곳에 모인 기사들은 불타버린 여덟 대륙에서 모인 자들입니다.","JPN":"ここに集まった騎士たちは皆、燃えてしまった八つの大陸から来ました。","ENG":"These knights came from the eight scorched continents.","TWN":"聚集在這裡的騎士們是從被燒毀的八大洲聚集而來的。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"본래라면 전장에서 그 명을 다해야 하나, 공포에 굴복해 고향을 버리고 도망쳐 온 패배자들이며.","JPN":"本来なら戦場で命を落とすべきでしたが、恐怖に屈して故郷を捨てて逃げてきた敗北者であり。","ENG":"We should have died on the battlefield, but we ran in fear.","TWN":"本來應該在戰場上完成使命，但卻因恐懼而屈服，拋棄故鄉逃跑的失敗者。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"재능도 어중간한 탓에 구원기사단이 되지 못한 나약한 존재들이죠.","JPN":"中途半端な才能であるがゆえに、救世騎士団に入れなかった弱い存在です。","ENG":"Too lacking in talent to join the Knights of Redemption, too weak to stand our ground.","TWN":"因為才能平庸，所以無法成為救贖騎士團的弱者。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제가 할 말은 아니라고 생각합니다만.","JPN":"私がこんなことを言っていいかはわかりませんが。","ENG":"It's not my place, but...","TWN":"我覺得這不是我該說的話。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"자신의 나약함을 마주볼 수 있다는 것은 큰 용기라고 생각합니다.","JPN":"自分の弱さと向き合うのはとても勇気のいることだと思います。","ENG":"Facing your own weakness takes real courage.","TWN":"我認為能夠面對自己的軟弱是一種巨大的勇氣。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건 페론 경이 나약하지 않다는 반증이겠죠.","JPN":"それはペロン卿が弱くはないという反証でしょう。","ENG":"That alone proves you're not weak, Sir Ferron.","TWN":"那正是證明費隆卿並不軟弱的證據吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"……예. 그레이스 경께서도 그렇게 말씀하셨습니다.","JPN":"……はい。グレース卿もそうおっしゃってくださいました。","ENG":"...Yes. Dame Grace said the same.","TWN":"……是的。葛瑞絲小姐也是這麼說的。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"무가치한 삶을 놓으려던 저희에게 무구를 쥐여 주시고 싸우는 방법과 용기를 건네셨죠.","JPN":"あの方は、価値のない人生を諦めようとしていた私たちに武具を渡し、戦う方法と勇気をくれました。","ENG":"She gave us weapons when we had nothing left. She taught us to fight and gave us courage.","TWN":"在我們想要放棄無意義的生活時，她將武器交給我們，並給予我們戰鬥的方法和勇氣。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그것으로 충성을 맹세할 이유는 충분합니다.","JPN":"それだけでも忠誠を誓う理由は十分です。","ENG":"That alone was more than enough to earn our loyalty.","TWN":"有足夠的理由以此宣誓效忠。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"끝난 것이나 다름없던 저희의 삶을, 저분께서는 함께 짊어져 주셨으니까요.","JPN":"終わったも同然だった私たちの人生を、あの方は共に背負ってくださったのですから。","ENG":"She chose to carry the burden of our broken lives with us.","TWN":"因為她願意與我們共同承擔，拯救了我們幾乎已經結束的生命。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"총대장, 페론. 설령 어떤 어둠이 우리를 맞이한들.","JPN":"総隊長、ペロン。たとえどんな闇が待ち受けようとも。","ENG":"General Ferron. No matter what darkness we face...","TWN":"我是總隊長，費隆。即便有任何黑暗迎接我們。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그 끝에 비로소, 우리에게 맡겨진 사명을 완수하리라 맹세합니다.","JPN":"最後には私たちに課せられた使命を完遂すると誓います。","ENG":"We swear to fulfill the mission we've been given.","TWN":"在終點，我發誓會完成我們被賦予的使命。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"가문의 후계자로서 소임을 다하기 위해 감히 여러분의 목숨을 걸겠습니다.","JPN":"一族の後継者としての役目を果たすため、皆さんの命をかけましょう。","ENG":"As heir to House Birmingham, I place your lives on the line to fulfill my duty.","TWN":"作為家族的繼承人，我將不惜以各位的生命為代價，履行我的職責。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부디…….","JPN":"どうか……","ENG":"Please...","TWN":"拜託……"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"지금의 <color=#ffd34c>선택</color>이.","JPN":"今の<color=#ffd34c>選択</color>が。","ENG":"Let this <color=#ffd34c>choice</color>...","TWN":"現在的這個<color=#ffd34c>選擇。</color>"},"stage":{"bg":"MS_1118","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FILM"},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"먼 훗날의 모두를 구원할 수 있기를.","JPN":"遠い未来の貴方たちを救えますように。","ENG":"Be what saves us all.","TWN":"願能拯救未來的所有人。"},"stage":{"bg":"MS_1118","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};